.darma-loader-darma-custom-092 {
  width: 40px;
  aspect-ratio: 1;
  color: var(--loader-color, #514b82);
  background: repeating-conic-gradient(from -47deg,#0000 0deg, currentColor 1deg 91deg,#0000 94deg 180deg);
  display: flex;
  animation: darma-loader-darma-custom-092-darma-loader-darma-custom-092-l12-0 2s infinite linear;
}
.darma-loader-darma-custom-092::before,
.darma-loader-darma-custom-092::after {
  content: "";
  flex: 1;
  background: currentColor;
  clip-path: polygon(0 0,100% 50%, 0 100%);
  animation: darma-loader-darma-custom-092-l12 1s infinite alternate;
  transform-origin: bottom left;
}
.darma-loader-darma-custom-092::after {
  clip-path: polygon(100% 0,100% 100%,0 50%);
  transform-origin: top right;
}
@keyframes darma-loader-darma-custom-092-l12-0 {
    0%,49.9% {transform:scaleX( 1)}
    50%,100% {transform:scaleX(-1)}
}
@keyframes darma-loader-darma-custom-092-l12 {
    0%, 20%  {transform:rotate(0deg)}
    80%,100% {transform:rotate(-270deg)}
}

